model.jaffle_shop.int_product_stock_leve.raw_code:
{{
    config(
        materialized='incremental',
        unique_key='product_store_key'
    )
}}

with movements as (
    select * from {{ ref('int_inventory_movements') }}
),

stock as (
    select
        product_id || '-' || store_id as product_store_key,
        product_id,
        store_id,
        sum(quantity_in) as total_received,
        sum(quantity_out) as total_sold,
        sum(quantity_in) - sum(quantity_out) as current_stock,
        max(case when movement_type = 'supply' then movement_date end) as last_restock_date,
        max(case when movement_type = 'sale' then movement_date end) as last_sale_date
    from movements

    {% if is_incremental() %}
    where movement_date > (select max(coalesce(last_restock_date, last_sale_date)) from {{ this }})
    {% endif %}

    group by product_id, store_id
)

select * from stock

model.jaffle_shop.orders.raw_code:
{% set payment_methods = ['credit_card', 'coupon', 'bank_transfer', 'gift_card'] %}

with orders as (

    select * from {{ ref('stg_orders') }}

),

payments as (

    select * from {{ ref('stg_payments') }}

),

order_payments as (

    select
        order_id,

        {% for payment_method in payment_methods -%}
        sum(case when payment_method = '{{ payment_method }}' then amount else 0 end) as {{ payment_method }}_amount,
        {% endfor -%}

        sum(amount) as total_amount

    from payments

    group by order_id

),

final as (

    select
        orders.order_id,
        orders.customer_id,
        orders.order_date,
        orders.status,

        {% for payment_method in payment_methods -%}

        order_payments.{{ payment_method }}_amount,

        {% endfor -%}

        order_payments.total_amount as amount

    from orders


    left join order_payments
        on orders.order_id = order_payments.order_id

)

select * from final

model.jaffle_shop.customer_cohorts.raw_code:
with first_last as (
    select * from {{ ref('int_customer_first_last_orders') }}
),

cohorts as (
    select
        {{ dbt.date_trunc('month', 'first_order_date') }} as cohort_month,
        count(*) as cohort_size,
        avg(lifetime_orders) as avg_lifetime_orders,
        avg(customer_tenure_days) as avg_tenure_days
    from first_last
    group by {{ dbt.date_trunc('month', 'first_order_date') }}
)

select * from cohorts

model.jaffle_shop.int_daily_order_summar.raw_code:
{{
    config(
        materialized='incremental',
        unique_key='order_date'
    )
}}

with orders as (
    select * from {{ ref('int_order_enriched') }}
),

daily as (
    select
        order_date,
        count(*) as order_count,
        count(distinct customer_id) as unique_customers,
        sum(subtotal) as total_revenue,
        sum(total_cost) as total_cost,
        sum(total_margin) as total_margin,
        sum(total_quantity) as total_items_sold,
        sum(case when has_promotion then 1 else 0 end) as promoted_orders,
        sum(discount_amount) as total_discounts,
        avg(subtotal) as avg_order_value
    from orders

    {% if is_incremental() %}
    where order_date > (select max(order_date) from {{ this }})
    {% endif %}

    group by order_date
)

select * from daily
